const { CosmosClient } = require("@azure/cosmos");
const { app, timerTrigger } = require("@azure/functions");

// Initialize Cosmos DB client with connection string from environment
const cosmosClient = new CosmosClient(process.env.COSMOS_DB_CONNECTION_STRING);

// Function to process batch data
app.timerTrigger("batchProcessor", {
    schedule: "0 */5 * * * *", // Every 5 minutes
    handler: async function (context, myTimer) {
        const startTime = new Date();
        context.log(`Batch processing started at: ${startTime.toISOString()}`);
        
        try {
            // Use connection pooling and proper resource management
            const container = cosmosClient.database("myDatabase").container("myContainer");
            
            // Process data in batches to avoid timeouts
            const batchSize = 1000;
            let continuationToken = null;
            let processedCount = 0;
            
            do {
                // Check if we're approaching timeout
                const elapsed = Date.now() - startTime.getTime();
                if (elapsed > 550000) { // 9 minutes 10 seconds to leave buffer
                    context.log("Approaching timeout, pausing batch processing");
                    break;
                }
                
                // Query with continuation token for large datasets
                const query = {
                    query: "SELECT * FROM c WHERE c.processed = false",
                    parameters: [],
                    continuation: continuationToken
                };
                
                const { resources, continuationToken: newContinuationToken } = 
                    await container.items.query(query, { maxItemCount: batchSize });
                
                continuationToken = newContinuationToken;
                
                if (resources.length === 0) {
                    break;
                }
                
                // Process batch items
                const batchOperations = [];
                for (const item of resources) {
                    try {
                        // Process individual item
                        const processedItem = await processItem(item);
                        batchOperations.push({
                            operationType: "Replace",
                            resourceBody: processedItem
                        });
                    } catch (error) {
                        context.log.error(`Error processing item ${item.id}:`, error);
                        // Continue with other items
                    }
                }
                
                // Execute batch operations
                if (batchOperations.length > 0) {
                    await container.items.batch(batchOperations);
                    processedCount += resources.length;
                }
                
                context.log(`Processed batch: ${processedCount} items`);
                
            } while (continuationToken);
            
            context.log(`Batch processing completed. Total items processed: ${processedCount}`);
            
        } catch (error) {
            context.log.error("Batch processing error:", error);
            throw error;
        }
    }
});

